let arrFavoriteEmojis = JSON.parse(localStorage.getItem('favoriteEmojis') || '[]');
let arrRecentEmojis = JSON.parse(localStorage.getItem('recentEmojis') || '[]');

// Apply some runtime changes to our EmojiDEX
for (cEmoji of arrEmojis) {
    // Force everything in to lowercase
    cEmoji.name = cEmoji.name.toLowerCase();

    // Add our 'used' integer to track usage for personalised emoji lists
    cEmoji.used = 0;
}

/**
 * Search emojis with fuzzy matching for typos
 * @param {string} search - Search term
 */
function searchEmojis(search) {
    if (!search || search.length < 1) return [];
    
    search = search.toLowerCase();
    const results = [];
    
    for (const emojiData of arrEmojis) {
        const name = emojiData.name.toLowerCase();
        const words = name.split(' ');
        
        let bestMatch = null;
        
        for (const word of words) {
            // Exact match - highest priority
            if (word === search) {
                bestMatch = { score: 0, word };
                break;
            }
            
            // Word starts with search
            if (word.startsWith(search) && search.length >= 2) {
                const score = 0.1;
                if (!bestMatch || score < bestMatch.score) {
                    bestMatch = { score, word };
                }
            }
            
            // Fuzzy matching for 3+ character searches
            if (search.length >= 3) {
                const lengthDiff = Math.abs(word.length - search.length);
                
                // Check words with similar length
                if (lengthDiff <= 1) {
                    const distance = levenshteinDistance(word, search);
                    
                    if (distance === 1) {
                        // Verify sufficient character overlap
                        const searchChars = new Set(search);
                        const wordChars = new Set(word);
                        const commonChars = [...searchChars].filter(c => wordChars.has(c)).length;
                        
                        if (commonChars >= search.length - 1) {
                            let score = 0.5;
                            
                            // Better score for missing letter at end (hart → heart)
                            if (word.length > search.length && word.startsWith(search)) {
                                score = 0.3;
                            }
                            // Better score for missing letter in middle
                            else if (word.length > search.length && 
                                     word[0] === search[0] && 
                                     word[word.length-1] === search[search.length-1]) {
                                score = 0.35;
                            }
                            
                            if (!bestMatch || score < bestMatch.score) {
                                bestMatch = { score, word };
                            }
                        }
                    }
                }
                
                // Check if search matches beginning of longer words
                if (word.length > search.length && lengthDiff <= 3) {
                    const wordStart = word.substring(0, search.length);
                    const distance = levenshteinDistance(wordStart, search);
                    
                    if (distance === 1) {
                        const score = 0.6;
                        if (!bestMatch || score < bestMatch.score) {
                            bestMatch = { score, word };
                        }
                    }
                }
            }
            
            // For 5+ character searches, allow distance 2
            if (search.length >= 5) {
                const distance = levenshteinDistance(word, search);
                if (distance === 2 && Math.abs(word.length - search.length) <= 1) {
                    const score = 0.8;
                    if (!bestMatch || score < bestMatch.score) {
                        bestMatch = { score, word };
                    }
                }
            }
        }
        
        if (bestMatch) {
            results.push({
                ...emojiData,
                score: bestMatch.score,
                matchedWord: bestMatch.word
            });
        }
    }
    
    // If no results found, fall back to includes search
    if (results.length === 0) {
        for (const emojiData of arrEmojis) {
            const name = emojiData.name.toLowerCase();
            if (name.includes(search)) {
                results.push({
                    ...emojiData,
                    score: 1.0, // Lower priority than fuzzy matches
                    matchedWord: name
                });
            }
        }
    }
    
    // Sort by relevance
    return results
        .sort((a, b) => {
            if (Math.abs(a.score - b.score) > 0.01) return a.score - b.score;
            
            // For same scores, prefer shorter matched words
            const aLen = a.matchedWord.length;
            const bLen = b.matchedWord.length;
            if (aLen !== bLen) return aLen - bLen;
            
            return a.matchedWord.localeCompare(b.matchedWord);
        })
        .map(({ score, matchedWord, ...emoji }) => emoji);
}

/** Return our most used emojis */
function getMostUsedEmojis() {
    return arrEmojis.sort((a, b) => b.used - a.used);
}

/**
 * Checks if the given string consists only of emojis, ignoring whitespace.
 * 
 * @param {string} str - The string to check for emojis.
 * @returns {boolean} True if the string contains only emojis (ignoring whitespace), false otherwise.
 */
/** Set of all emoji strings from our dataset, for fast lookup in isEmojiOnly. */
const emojiDataSet = new Set(arrEmojis.map(e => e.emoji));

function isEmojiOnly(str) {
    // Remove all whitespace from the string
    const strWithoutSpace = str.replace(/\s/g, '');

    // If the string is empty after removing whitespace, return false
    if (strWithoutSpace.length === 0) return false;

    // Use Intl.Segmenter to properly split the string into graphemes (including emoji sequences)
    const segmenter = new Intl.Segmenter(undefined, { granularity: 'grapheme' });
    const segments = [...segmenter.segment(strWithoutSpace)].map(s => s.segment);

    // Check if each segment is an emoji
    return segments.every(segment => {
        // Test for emoji property (Unicode regex — may miss newer emojis on older engines)
        if (/\p{Emoji_Presentation}/u.test(segment)) return true;
        // Handle basic emojis that need variation selectors
        if (/\p{Emoji}/u.test(segment) && !/\p{Number}|\p{Letter}/u.test(segment)) return true;
        // Fallback: check against our own emoji dataset (covers newer emojis on older Android WebViews)
        return emojiDataSet.has(segment);
    });
}

/**
 * Converts an ISO 3166-1 alpha-2 country code to its corresponding flag emoji.
 * @param {string} isoCode - The two-letter ISO country code
 * @returns {string} The flag emoji or a globe emoji if invalid
 */
function isoToFlagEmoji(isoCode) {
    if (!isoCode || isoCode.length !== 2) return '🌍';
    
    const upperIso = isoCode.toUpperCase();
    const codePointA = upperIso.charCodeAt(0) - 65 + 0x1F1E6;
    const codePointB = upperIso.charCodeAt(1) - 65 + 0x1F1E6;
    
    return String.fromCodePoint(codePointA, codePointB);
}

/**
 * Convert all Unicode emojis in the given DOM element to Twemoji SVGs
 * @param {HTMLElement} domElement
 * @param {{ layoutHint?: boolean }} [opts] — when layoutHint is true, stamp
 *        inline 1em sizing + load handler that forces a reflow on the nearest
 *        .cutoff ancestor. Required for ellipsis-truncated text containers
 *        (chatlist preview) where layout reserves 0×0 for the unloaded image,
 *        text fills the line, then the SVG paints over already-laid-out text
 *        once it resolves. Off by default — picker grids and other contexts
 *        size emojis via dedicated CSS rules.
 */
function twemojify(domElement, opts) {
    // Strip skin tone modifiers from text nodes — our Twemoji set only has neutral/yellow variants.
    // Also normalize ZWJ sequences whose Twemoji regex entry omits FE0F variation selectors
    // that platforms (macOS, iOS) include in fully-qualified input. Without this, the regex
    // splits the sequence into its component emojis and renders them separately.
    const walker = document.createTreeWalker(domElement, NodeFilter.SHOW_TEXT);
    while (walker.nextNode()) {
        const node = walker.currentNode;
        let next = node.textContent.replace(/[\u{1F3FB}-\u{1F3FF}]/gu, '');
        // 👁️‍🗨️ eye-in-speech-bubble (1F441 FE0F? 200D 1F5E8 FE0F?) → unqualified form
        next = next.replace(/\u{1F441}\u{FE0F}?\u{200D}\u{1F5E8}\u{FE0F}?/gu, '\u{1F441}\u{200D}\u{1F5E8}');
        if (next !== node.textContent) node.textContent = next;
    }
    twemoji.parse(domElement, { callback: (icon, _) => '/twemoji/svg/' + icon + '.svg' });
    if (!opts || !opts.layoutHint) return;
    const imgs = domElement.querySelectorAll('img.emoji:not([data-sized])');
    for (const img of imgs) {
        img.style.width = '1em';
        img.style.height = '1em';
        img.setAttribute('data-sized', '');
        if (img.complete && img.naturalWidth > 0) continue;
        img.addEventListener('load', () => {
            const cutoff = img.closest('.cutoff');
            if (!cutoff) return;
            // display:none → reflow → restore. Hard-resets the box layout so
            // the truncation algorithm can't reuse a stale calculation done
            // against an unknown-dimension image. Softer tricks (toggling
            // text-overflow, reading offsetWidth alone) leave WebKit's
            // ellipsis cache intact and the bug persists.
            const prev = cutoff.style.display;
            cutoff.style.display = 'none';
            void cutoff.offsetHeight;
            cutoff.style.display = prev;
        }, { once: true });
    }
}

function addToRecentEmojis(emoji) {
  // Remove if already exists
  arrRecentEmojis = arrRecentEmojis.filter(e => e.emoji !== emoji.emoji);
  // Add to beginning
  arrRecentEmojis.unshift(emoji);
  // Keep only last 20
  arrRecentEmojis = arrRecentEmojis.slice(0, 20);
  localStorage.setItem('recentEmojis', JSON.stringify(arrRecentEmojis));
}

function toggleFavoriteEmoji(emoji) {
  const index = arrFavoriteEmojis.findIndex(e => e.emoji === emoji.emoji);
  if (index >= 0) {
    arrFavoriteEmojis.splice(index, 1);
  } else {
    arrFavoriteEmojis.push(emoji);
  }
  localStorage.setItem('favoriteEmojis', JSON.stringify(arrFavoriteEmojis));
  return index < 0; // Returns true if added, false if removed
}